import{_ as d,o as e,c as r,ag as n}from"./chunks/framework.DXGyWiRo.js";const i="/images/uebung023.jpg",a="/images/uebung024.jpg",k=JSON.parse('{"title":"Übung Lektion 16","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung16.md","filePath":"lektionen/uebung16.md"}'),h={name:"lektionen/uebung16.md"};function s(l,t,o,p,u,m){return e(),r("div",null,[...t[0]||(t[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-16" tabindex="-1">Übung Lektion 16 <a class="header-anchor" href="#ubung-lektion-16" aria-label="Permalink to &quot;Übung Lektion 16&quot;">​</a></h1><p>A) Wandeln sie folgende Ausdrücke in Tatpuruṣa um und übersetzen Sie sie:</p><p>१. देवस्य पुरुषः । देवपुरुषः</p><p>२. गुणवती ब्राह्मणी । गुणवद्ब्राह्मणी</p><p>३. सत्यवान्ब्राह्मणः । सत्यवद्ब्राह्मणः</p><p>४. पशुमन्तो जनाः । पशुमज्जनाः</p><p>५. सुखवान्वैश्यायाः पुत्रः ।</p><p>६.  सुखवत्या वैश्यायाः पुत्रः । सुखवद्वैश्यापुत्रः</p><p>७. कवेरुक्त्याः सत्यम् । कव्युक्तिसत्यम्</p><p>८. शिवेन रक्षिता बाला । शिवरक्षितबाला</p><p>९. रामेण पीतं जलम् । रामपीतजलम्</p><p>१०. फलवांल्लाभः । फलवद्लाभः</p><p>११. इष्टाया देवतायाः पूजा । इष्टदेवतापूजा</p><p>१२. देवानां स्तुतिः । देवस्तुतिः</p><p>B) Lösen Sie in folgenden Sätzen alle Komposita in Sanskrit auf, bilden Sie so Sätze mit flektierten Nomina und übersetzen Sie:</p><p>१. पुण्यवद्वैश्यपुत्रो देवेन्द्रलोकं गच्छति । पुण्यवान्वैश्यस्य पुत्रो देवानामिन्द्रस्य लोकं गच्छति । पुण्यवतो वैश्यस्य पुत्रो देवानामिन्द्रस्य लोकं गच्छति । ... देवानामिन्द्राणां लोकं गच्छति । Der verdienstvolle Sohn eines Vaiśya kommt in den Himmel des Götterfürsten. Der Sohn eines verdienstvollen Vaiśya kommt in den Himmel des Götterfürsten. ... kommt in den Himmel der Götterfürsten.</p><p>२. पुण्यकरणं स्वर्गमार्गः । पुण्यस्य करणं स्वर्गस्य मार्गः । पुण्यानां करणं स्वर्गं मार्गः । Tun von Verdienstlichem ist der Weg zum Himmel.</p><p>३. न साधुः पशुवन्नरधेनुलोभः । न साधुः पशुवतो नरस्य धेनूनां लोभः । ... धेनोर्लोभः । न साधुः पशुवतां नराणां धेनूनां लोभः । Die Gier des an Vieh reichen Mannes nach Kühen / nach einer / der Kuh ist nicht gut.  Die Gier von an Vieh reichen Männern nach Kühen ist nicht gut.</p><p>४. न पशुयज्ञैर्नराः स्वर्गं गच्छन्ति । धर्मयज्ञैस्तु स्वर्गसुखमाप्नुवन्ति । न पशूनां यज्ञैर्नराः स्वर्गं गच्छन्ति । धर्मस्य यज्ञैस्तु स्वर्गस्य / स्वर्गानां सुखमाप्नुवन्ति । Mit Tieropfern kommen Menschen nicht in den Himmel.  Mit (unblutigen) Opfern der Gerechtigkeit aber erreichen sie himmlisches Glück.</p><p>५. द्विजदासा इति शूद्रा उच्यन्ते । द्विजानां दासा इति शूद्रा उच्यन्ते । Śūdras nennt man Sklaven der Zweimalgeborenen.</p><p>६. बालब्राह्मणपुत्राः सत्यवन्नरं शृण्वन्ति । बा्ला ब्राह्मणानां पुत्राः स्त्यवन्तं नरं शृण्वन्ति । Die jungen Brahmanenöhne hören auf den wahrhaftigen Mann.</p><p>७. बलवत्क्षत्रिया धनवच्छत्रुनगरं जयन्ति । बलवन्तः क्षत्रिया धनवतां शत्रूनां नगरं जयन्ति । बलवन्तः क्षत्रिया धनवच्छ्त्रूनां नगरं जयन्ति । Die mächtigen Kṣatriyas besiegen die Stadt der reichen Feinde. Die mächtigen Kṣatriyas besiegen die reiche Stadt der Feinde.</p><p>८. ऋष्युक्त्या सत्यमुच्यते । ऋषीणामुक्त्या सत्यमुच्यते । ऋषेरुक्त्या सत्यमुच्यते । Das Wort der vedischen Weisen sagt die Wahrheit. Das Wort des vedischen Weisen sagt die Wahrheit.</p><p>९. बलवद्योधा ब्राह्मणग्रामं गताः । बलवन्तो योधा ब्राह्मणानां / ब्राह्मणस्य ग्रामं गताः । Die starken Krieger sind ins Brahmanendorf / Dorf des Brahmanen gegangen.</p><p>१०. पुण्यवद्वैश्येष्टवेवतापूजां करोति । पुन्यवतो वैश्यस्येष्टाया देवतायाः पूजां करोति । पुन्यवती वैश्येष्ताया देवतायाः पूजां करोति । Er verehrt die persönliche Gottheit des verdienstvollen Vaiśya / der verdienstvollen Vaiśyafrau. Die verdienstvolle Vaiśyafrau verehrt ihre persönliche Gottheit.</p><p><img src="'+i+'" alt=""><br> Abb.: न पशुयज्ञैर्नराः स्वर्गं गच्छन्ति<br> Dakshinkali = दक्षिनाकाली, Nepal = नेपाल<br> [Bildquelle: Mathew Knott. -- <a href="http://www.flickr.com/photos/mknott/1394930047/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/mknott/1394930047/</a>. -- Zugriff am 2008-12-22. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>A) Bilden Sie alle bisher gelernten Kasus zu folgenden Wörtern als Beispiele für die bisher gelernten Deklinationsklassen.</p><p>Lernen Sie die Deklinationsmuster nach diesen Beispielen auswendig!!!</p><p>१. नर m.</p><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td>1. Nom.</td><td>नरस्</td><td>नरास्</td></tr><tr><td>2. Akk.</td><td>नरम्</td><td>नरान्</td></tr><tr><td>3. Instr.</td><td>नरेण</td><td>नरैस्</td></tr><tr><td>6. Gen.</td><td>नरस्य</td><td>नराणाम्</td></tr></tbody></table><p>२. फल n.</p><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td>1. Nom.</td><td>फलम्</td><td>फलानि</td></tr><tr><td>2. Akk.</td><td>फलम्</td><td>फलानि</td></tr><tr><td>3. Instr.</td><td>फलेन</td><td>फलैस्</td></tr><tr><td>6. Gen.</td><td>फलस्य</td><td>फलानाम्</td></tr></tbody></table><p>३. क्षत्रिया f.</p><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td>1. Nom.</td><td>क्षत्रिया</td><td>क्षत्रियास्</td></tr><tr><td>2. Akk.</td><td>क्षत्रियाम्</td><td>क्षत्रियास्</td></tr><tr><td>3. Instr.</td><td>क्षत्रियया</td><td>क्षत्रियाभिस्</td></tr><tr><td>6. Gen.</td><td>क्षत्रियायास्</td><td>क्षत्रियाणाम्</td></tr></tbody></table><p>४. अरि m.</p><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td>1. Nom.</td><td>अरिस्</td><td>अरयस्</td></tr><tr><td>2. Akk.</td><td>अरिम्</td><td>अरीन्</td></tr><tr><td>3. Instr.</td><td>अरिणा</td><td>अरिभिस्</td></tr><tr><td>6. Gen.</td><td>अरेस्</td><td>अरीणाम्</td></tr></tbody></table><p>५. मति f.</p><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td>1. Nom.</td><td>मतिस्</td><td>मतयस्</td></tr><tr><td>2. Akk.</td><td>मतिम्</td><td>मतीस्</td></tr><tr><td>3. Instr.</td><td>मत्या</td><td>मतिभिस्</td></tr><tr><td>6. Gen.</td><td>मतेस्</td><td></td></tr><tr><td>मत्यास्</td><td>मतीनाम्</td><td></td></tr></tbody></table><p>६. गुरु m.</p><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td>1. Nom.</td><td>गुरुस्</td><td>गुरवस्</td></tr><tr><td>2. Akk.</td><td>गुरुम्</td><td>गुरून्</td></tr><tr><td>3. Instr.</td><td>गुरुणा</td><td>गुरुभिस्</td></tr><tr><td>6. Gen.</td><td>गुरोस्</td><td>गुरूणाम्</td></tr></tbody></table><p>७. धेनु f.</p><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td>1. Nom.</td><td>धेनुस्</td><td>धेनवस्</td></tr><tr><td>2. Akk.</td><td>धेनुम्</td><td>धेनूस्</td></tr><tr><td>3. Instr.</td><td>धेन्वा</td><td>धेनुभिस्</td></tr><tr><td>6. Gen.</td><td>धेनोस्</td><td></td></tr><tr><td>धेन्वास्</td><td>धेनूनाम्</td><td></td></tr></tbody></table><p>८. देवी f.</p><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td>1. Nom.</td><td>देवी</td><td>देव्यस्</td></tr><tr><td>2. Akk.</td><td>देवीम्</td><td>देवीस्</td></tr><tr><td>3. Instr.</td><td>देव्या</td><td>देवीभिस्</td></tr><tr><td>6. Gen.</td><td>देव्यास्</td><td>देवीनाम्</td></tr></tbody></table><p>९. गुणवन्त् m.</p><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td>1. Nom.</td><td>गुणवान्</td><td>गुणवन्तस्</td></tr><tr><td>2. Akk.</td><td>गुणवन्तम्</td><td>गुणवतस्</td></tr><tr><td>3. Instr.</td><td>गुणवता</td><td>गुणवद्भिस्</td></tr><tr><td>6. Gen.</td><td>गुणवतस्</td><td>गुण्वताम्</td></tr></tbody></table><p>गुणवन्त् n.</p><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td>1. Nom.</td><td>गुणवत्</td><td>गुणवन्ति</td></tr><tr><td>2. Akk.</td><td>गूनवत्</td><td>गुणवन्ति</td></tr><tr><td>3. Instr.</td><td>गुणवता</td><td>गुणवद्भिस्</td></tr><tr><td>6. Gen.</td><td>गुणवतस्</td><td>गुण्वताम्</td></tr></tbody></table><p>गुणवती f. dekliniert wie देवी</p><p>१०. किम्  m., n., f.</p><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td></td><td>Maskulinum</td><td>Neutrum</td></tr><tr><td>1. Nom.</td><td>कस्</td><td>किम्</td></tr><tr><td>2. Akk.</td><td>कम्</td><td>किम्</td></tr><tr><td>3. Instr.</td><td>केन</td><td>कया</td></tr><tr><td>6. Gen.</td><td>कस्य</td><td>कस्यास्</td></tr></tbody></table><p>११. तद् m., n., f.</p><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td></td><td>Maskulinum</td><td>Neutrum</td></tr><tr><td>1. Nom.</td><td>स</td><td></td></tr><tr><td>सो</td><td></td><td></td></tr><tr><td>सः</td><td>तद्</td><td>सा</td></tr><tr><td>2. Akk.</td><td>तम्</td><td>तद्</td></tr><tr><td>3. Instr.</td><td>तेन</td><td>तया</td></tr><tr><td>6. Gen.</td><td>तस्य</td><td>तस्यास्</td></tr></tbody></table><p>१२. एतद् m., n., f.</p><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td></td><td>Maskulinum</td><td>Neutrum</td></tr><tr><td>1. Nom.</td><td>एष</td><td></td></tr><tr><td>एषो</td><td></td><td></td></tr><tr><td>एषः</td><td>एतद्</td><td>एषा</td></tr><tr><td>2. Akk.</td><td>एतम्</td><td></td></tr><tr><td>एनम्</td><td>एतद्</td><td></td></tr><tr><td>एनद्</td><td>एताम्</td><td></td></tr><tr><td>एनाम्</td><td>एतान्</td><td></td></tr><tr><td>एनान्</td><td>एतानि</td><td></td></tr><tr><td>एनानि</td><td>एतास्</td><td></td></tr><tr><td>एनास्</td><td></td><td></td></tr><tr><td>3. Instr.</td><td>एतेन</td><td></td></tr><tr><td>एनेन</td><td>एतया</td><td></td></tr><tr><td>एनया</td><td>तैस्</td><td>ताभिस्</td></tr><tr><td>6. Gen.</td><td>एतस्य</td><td>तस्यास्</td></tr></tbody></table><p>१३. इदम् m., n., f.</p><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td></td><td>Maskulinum</td><td>Neutrum</td></tr><tr><td>1. Nom.</td><td>अयम्</td><td>इदम्</td></tr><tr><td>2. Akk.</td><td>इमम्</td><td></td></tr><tr><td>एनम्</td><td>इदम्</td><td></td></tr><tr><td>एनद्</td><td>इमाम्</td><td></td></tr><tr><td>एनाम्</td><td>इमान्</td><td></td></tr><tr><td>एनान्</td><td>इमानि</td><td></td></tr><tr><td>एनानि</td><td>इमास्</td><td></td></tr><tr><td>एनास्</td><td></td><td></td></tr><tr><td>3. Instr.</td><td>अनेन</td><td></td></tr><tr><td>एनेन</td><td>अनया</td><td></td></tr><tr><td>एनया</td><td>एभिस्</td><td>आभिस्</td></tr><tr><td>6. Gen.</td><td>अस्य</td><td>अस्यास्</td></tr></tbody></table><p>B) Übersetzen Sie und lösen Sie alle Komposita in Sanskrit auf:</p><p>१. योगश्चित्तवृत्तिनिरोधः ॥योगसूत्र १.२॥ योगश्चित्तस्य वृत्तेर्निरोधः / वृत्तीनां निरोधः । Yoga ist das Stoppen der mentalen Tätigkeit / Tätigkeiten.</p><p>२. स्वधर्मो ब्राह्मणस्याध्ययनमध्यापनं यजनं याजनं दानं प्रतिग्रहश्च ॥५॥ Die spezifische Pflicht des Brahmanen ist: Vedastudium, Vedaunterricht, Opfern als Opferherr, Opfern in fremdem Auftrag, Geben an Brahmanen, Empfang von Gaben.</p><p>क्षत्रियस्याध्ययनं यजनं दानं शस्त्राजीवो भूतरक्षणं च ॥६॥ क्षत्रियस्याध्ययनं यजनं दानं शास्त्रेणाजीवो / शास्त्रस्याजीवो भूतानां रक्षणं च् । Die spezifische Pflicht eines Kṣatriya ist: Vedastudium, Opfern als Opferherr, Geben an Brahmanen, Lebensunterhalt durch das Schwert, Hüten der Lebewesen.</p><p>वैश्यस्याध्ययनं यजनं दानं कृषिपाशुपाल्ये वणिज्या च ॥७॥ वैश्यस्याध्ययनं यजनं दानं कृषिः पाशुपाल्यं च वणिज्या च । Die spezifische Pflicht eines Vaiśya ist: Vedastudium, Opfern als Opferherr, Geben an Brahmanen, Ackerbau und Viehhaltung, Handel.</p><p>शूद्रस्य द्विजातिशुश्रूषा वार्त्ता कारुकुशीलवकर्म च ॥८॥ शुड्रस्य द्विजातीनां शुश्रूषा वार्त्ता कारूणां कुशीलवानां च कर्म । Die spezifische Pflicht eines Śūdra ist gehorsamer Dienst an den Zweimalgeborenen, Wirtschaftstätigkeit und Tätigkeit als Handwerker und Schausteller.</p><p>सर्वेषामहिंसा सत्यं शौचमनसूयानृशंस्यं क्षमा च ॥१३॥ Pflicht aller ist: Gewaltlosigkeit, Wahrhaftigkeit, Reinheit, Nicht über sein Los murren, Freisein von Boshaftigkeit und geduldige Nachsicht.</p><p>(कौटिलीयार्थशास्त्र १.३.५-८, १३)</p><blockquote><p>Erklärungen;</p><p>Satz 7: कृषिपाशुपाल्ये Dual, Nom. Akk.: Dvandva, das zwei &quot;Sachen&quot; bezeichnet</p><p>Satz 8: कर्म Nom., Akk. sg. Neutrum zu कर्मन् &quot;Tat&quot;</p><p>Satz 13: सर्वेषाम् Gen. pl. mask. zu सर्व &quot;jeder, alle&quot; (Pronomen, dekliniert nicht wie deva)</p></blockquote><p>३. आन्वीक्षिकीत्रयीवार्त्तानां योगक्षेमसाधनो दण्डः, तस्य नीतिर्दण्डनीतिः ॥ कौटिलीयार्थशास्त्र १.४.३ ॥ आन्वीक्षिक्याः त्रय्याः वार्त्ताया योगस्य क्षेमस्य च साधनो दण्डः, तस्य नीतिर्दण्डनीतिः । Der Prügel bewirkt Erwerb und sicheren Besitz von Philosophie, Vedististik und Ökonomie. Die Führung des Prügels ist Politik.</p><p><img src="'+a+'" alt=""><br> Abb.: योगश्चित्तवृत्तिनिरोधः<br> [Bildquelle: Roshnii. -- <a href="http://www.flickr.com/photos/roshnii/110087684/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/roshnii/110087684/</a>. -- Zugriff am 2008-12-22. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p>',69)])])}const g=d(h,[["render",s]]);export{k as __pageData,g as default};
